    Set<Node> nodesvisited = new HashSet<>(); // Initialize nodesvisited to avoid undefined variable
    queue.addLast(startnode);
    nodesvisited.add(startnode);
    while (!queue.isEmpty()) { // Change condition to avoid infinite loop if queue becomes empty
        Node node = queue.removeFirst();
        if (node == goalnode) {
            return true;
        } else {
            for (Node successor_node : node.getSuccessors()) {
                if (!nodesvisited.contains(successor_node)) {
                    queue.addLast(successor_node); // Use addLast to maintain BFS order
