    String line;
    while (text.length() > cols) {
        int end = text.lastIndexOf(" ", cols); 
        if (end == -1) {
            end = cols;
            line = text.substring(0, end);
            text = text.substring(end);
        } else {
            line = text.substring(0, end);
            text = text.substring(end + 1); // Skip the space
        }
        lines.add(line);
    }
    if (!text.isEmpty()) {
        lines.add(text); // Add the remaining text
    }
    return lines;
}

